import React, { useState, useRef, useEffect } from 'react';
import api from '../api/api';

const CalorieUpload = () => {
  const [filename, setFilename] = useState('rice.jpg');
  const [mealType, setMealType] = useState('Lunch');
  const [result, setResult] = useState(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const isMounted = useRef(true);

  useEffect(() => {
    // track mounted state to avoid updating state on an unmounted component
    isMounted.current = true;
    return () => {
      isMounted.current = false;
    };
  }, []);

  const handleSubmit = async (e) => {
    // This function can be used for both form onSubmit or button onClick.
    if (e && typeof e.preventDefault === 'function') e.preventDefault();

    // If you want to keep previous result visible until new one arrives,
    // do NOT call setResult(null) here. We'll keep the previous result until
    // the new result actually arrives.
    setLoading(true);
    setError('');

    const payload = {
      mealType,
      imageUrl: `/mock-images/${filename}`,
      filename: filename, // Key parameter for the mock Python service
    };

    try {
      const response = await api.post('/intake/upload-image', payload);
      // Protect against response arriving after unmount
      if (!isMounted.current) return;

      // Make sure response shape exists before using it
      const prediction = response?.data?.prediction ?? null;
      if (!prediction) {
        setError('No prediction returned from the server.');
      } else {
        setResult(prediction);
      }
    } catch (err) {
      if (!isMounted.current) return;
      console.error('Calorie estimation failed:', err?.response?.data ?? err);
      setError(err?.response?.data?.message || 'Estimation service is unavailable (Port 5001 down?)');
    } finally {
      if (!isMounted.current) return;
      setLoading(false);
    }
  };

  // Optional: explicit clear button so user can clear result manually
  const handleClear = () => {
    setResult(null);
    setError('');
  };

  return (
    <form
      // keep onSubmit in case parent expects a form, but we will preventDefault in handler
      onSubmit={handleSubmit}
      className="space-y-3 text-sm"
      onKeyDown={(e) => {
        // prevent Enter in inputs from accidentally submitting the whole page
        if (e.key === 'Enter' && (e.target.tagName === 'INPUT')) {
          e.preventDefault();
        }
      }}
    >
      <p className="text-xs text-gray-500 italic">
        *Mock: Enter a keyword (e.g., <strong>rice</strong>, <strong>dosa</strong>, <strong>chapati</strong>) to simulate image recognition.
      </p>

      <input
        type="text"
        placeholder="Simulated Filename (e.g., dosa.jpg)"
        value={filename}
        onChange={(e) => setFilename(e.target.value)}
        required
        className="input"
      />

      <select
        name="mealType"
        value={mealType}
        onChange={(e) => setMealType(e.target.value)}
        className="select"
      >
        <option value="Breakfast">Breakfast</option>
        <option value="Lunch">Lunch</option>
        <option value="Snack">Snack</option>
        <option value="Dinner">Dinner</option>
      </select>

      <div className="flex gap-2">
        {/* Use type="button" to avoid uncontrolled form submission side-effects */}
        <button
          type="button"
          onClick={handleSubmit}
          disabled={loading}
          className="flex-1 bg-orange-500 text-white p-2 rounded hover:bg-orange-600 disabled:bg-gray-400 shadow-sm"
        >
          {loading ? 'Estimating...' : 'Upload & Log Meal 🍽️'}
        </button>

        <button
          type="button"
          onClick={handleClear}
          disabled={loading}
          className="px-3 py-2 border rounded disabled:opacity-50"
        >
          Clear
        </button>
      </div>

      {error && <p className="text-red-500 mt-2">{error}</p>}

      {/* Display Results */}
      {result && (
        <div className="mt-4 p-3 border border-gray-200 rounded bg-orange-50">
          <p className="text-md font-bold">{result.foodName ?? 'Unknown food'}</p>
          <p>
            Estimated Calories:{' '}
            <span className="font-semibold text-orange-700">
              {result.caloriesEstimated ?? '—'} kcal
            </span>
          </p>
          <p className="text-xs">
            Macros:
            C:{result.macroBreakdown?.Carbohydrates ?? '—'}g |
            P:{result.macroBreakdown?.Protein ?? '—'}g |
            F:{result.macroBreakdown?.Fat ?? '—'}g
          </p>
        </div>
      )}
    </form>
  );
};

export default CalorieUpload;
